//SPDX-License-Identifier: MIT
pragma solidity ^0.8.25;

import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";
import {IBrand} from "./interface/IBrand.sol";

contract Campaign is Ownable {
    IBrand public s_brandContract;
    uint256 public idCampaign;

    struct CampaignStruct {
        uint256 idCampaign;
        uint256 idBrand;
        string name;
        uint256 amount;
        bool active;
        uint256 startDate;
        uint256 endDate;
    }

    mapping(uint256 => CampaignStruct) public s_campaigns;

    event CampaignCreated(uint256 indexed idCampaign, uint256 indexed idBrand, string name, uint256 amount);
    event CampaignUpdated(uint256 indexed idCampaign, string name, uint256 amount);

    constructor(address _brandContract) Ownable(msg.sender) {
        require(_brandContract != address(0), "Invalid brand contract address");
        s_brandContract = IBrand(_brandContract);
    }

    function createCampaign(
        uint256 _idBrand,
        string memory _name,
        uint256 _amount,
        uint256 _startDate,
        uint256 _endDate
    ) external onlyOwner {
        require(s_brandContract.isValidBrand(_idBrand), "Invalid brand");
        require(bytes(_name).length > 0, "Invalid campaign name");
        require(_endDate > _startDate, "Invalid dates");
        idCampaign++;
        CampaignStruct memory campaign = CampaignStruct({
            idCampaign: idCampaign,
            idBrand: _idBrand,
            name: _name,
            amount: _amount,
            active: true,
            startDate: _startDate,
            endDate: _endDate
        });
        s_campaigns[idCampaign] = campaign;
        emit CampaignCreated(idCampaign, _idBrand, _name, _amount);
    }

    function updateCampaign(
        uint256 _idCampaign,
        string memory _name,
        uint256 _amount,
        uint256 _startDate,
        uint256 _endDate
    ) external {
        CampaignStruct storage campaign = s_campaigns[_idCampaign];
        require(campaign.idCampaign != 0, "Campaign not found");
        require(bytes(_name).length > 0, "Invalid campaign name");
        require(_endDate > _startDate, "Invalid dates");
        campaign.name = _name;
        campaign.amount = _amount;
        campaign.startDate = _startDate;
        campaign.endDate = _endDate;
        emit CampaignUpdated(_idCampaign, _name, _amount);
    }

    function getCampaignById(uint256 _idCampaign)
        external
        view
        returns (uint256, uint256, string memory, uint256, bool, uint256, uint256)
    {
        require(isValidCampaign(_idCampaign), "Campaign ID invalid");
        CampaignStruct memory c = s_campaigns[_idCampaign];
        return (c.idCampaign, c.idBrand, c.name, c.amount, c.active, c.startDate, c.endDate);
    }

    function isValidCampaign(uint256 _idCampaign) public view returns (bool) {
        CampaignStruct memory c = s_campaigns[_idCampaign];
        require(_idCampaign <= idCampaign, "Invalid Campaign ID");
        require(c.idCampaign != 0, "Invalid Campaign");
        require(c.active, "Campaign inactive");
        require(block.timestamp <= c.endDate, "Campaign has ended");
        return true;
    }
}

src/interface/IBrand.sol.content:
pragma solidity ^0.8.25;

/// @title IBrand Interface
/// @notice Interface para la gestión de marcas.
/// @dev Define las funciones necesarias para crear y actualizar marcas.
interface IBrand {
    /// @notice Estructura que representa una marca.
    /// @param idBrand Identificador único de la marca.
    /// @param brandOwner Dirección del propietario de la marca.
    /// @param name Nombre de la marca.
    /// @param active Estado de la marca (activa o inactiva).
    struct BrandStruct {
        uint256 idBrand;
        address brandOwner;
        string name;
        bool active;
    }

    /// @notice Crea una nueva marca.
    /// @param _name Nombre de la marca.
    /// @param _brandOwner Dirección del propietario de la marca.
    function createBrand(string memory _name, address _brandOwner) external;

    /// @notice Actualiza una marca existente.
    /// @param _name Nuevo nombre de la marca.
    /// @param _brandOwner Nueva dirección del propietario de la marca.
    /// @param _idBrand Identificador de la marca a actualizar.
    function updateBrand(string memory _name, address _brandOwner, uint256 _idBrand) external;

    /// @notice Obtiene los detalles de una marca.
    /// @param _idBrand Identificador de la marca a obtener.
    /// @return idBrand Identificador único de la marca.
    /// @return brandOwner Dirección del propietario de la marca.
    /// @return name Nombre de la marca.
    /// @return active Estado de la marca (activa o inactiva).
    function getBrand(uint256 _idBrand)
        external
        view
        returns (uint256 idBrand, address brandOwner, string memory name, bool active);

    /// @notice Desactiva una marca.
    /// @param _idBrand Identificador de la marca a desactivar.
    function disableBrand(uint256 _idBrand) external;

    /// @notice Activa una marca.
    /// @param _idBrand Identificador de la marca a activar.
    function enableBrand(uint256 _idBrand) external;

    /// @notice Verifica si una marca es válida.
    /// @param _idBrand Identificador de la marca a verificar.
    /// @return Booleano que indica si la marca es válida.
    function isValidBrand(uint256 _idBrand) external view returns (bool);
}

src/KOL.sol.content:
//SPDX-License-Identifier: MIT
pragma solidity ^0.8.25;

import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";
import {Campaign} from "./Campaign.sol";

contract KOL is Ownable {
    Campaign public s_campaignContract;
    uint256 public idKolCampaign;

    struct KOLCampaign {
        address kol;
        uint256 idCampaign;
    }

    mapping(address => bool) public s_kols;
    mapping(uint256 => KOLCampaign) public s_kolCampaign;
    mapping(address => KOLCampaign[]) public s_campaignsKol;

    event KolCampaignAdded(uint256 indexed idKolCampaign, address indexed kol, uint256 idCampaign);
    event CampaignContractUpdated(address indexed campaignContract);
    event KolJoined(address indexed kol);

    constructor(address _campaignContract) Ownable(msg.sender) {
        require(_campaignContract != address(0), "Invalid campaign contract address");
        s_campaignContract = Campaign(_campaignContract);
    }

    function joinAsKol(address _address) external {
        require(_address != address(0), "Invalid KOL address");
        s_kols[_address] = true;
        emit KolJoined(_address);
    }

    function addKolToCampaign(uint256 _idCampaign) external {
        require(s_kols[msg.sender], "Invalid KOL");
        bool isValidCampaign = s_campaignContract.isValidCampaign(_idCampaign);
        require(isValidCampaign, "Invalid campaign");

        KOLCampaign memory kolCampaign = KOLCampaign({kol: msg.sender, idCampaign: _idCampaign});
        idKolCampaign++;
        s_kolCampaign[idKolCampaign] = kolCampaign;
        s_campaignsKol[msg.sender].push(kolCampaign);
        emit KolCampaignAdded(idKolCampaign, msg.sender, _idCampaign);
    }

    function updateCampaignContract(address _campaignContract) external onlyOwner {
        require(_campaignContract != address(0), "Invalid campaign contract address");
        s_campaignContract = Campaign(_campaignContract);
        emit CampaignContractUpdated(_campaignContract);
    }

    function getKOLCampaign(uint256 _id) public view returns (address, uint256) {
        require(isValidKolCampaign(_id), "Invalid KOLCampaign");
        KOLCampaign memory kc = s_kolCampaign[_id];
        return (kc.kol, kc.idCampaign);
    }

    function getKolCampaignsByAddress(address _kol) public view returns (KOLCampaign[] memory) {
        require(s_kols[_kol], "Invalid Kol");
        return s_campaignsKol[_kol];
    }

    function isValidKolCampaign(uint256 _id) public view returns (bool) {
        KOLCampaign memory kc = s_kolCampaign[_id];
        return kc.kol != address(0);
    }
}

